"use strict";module.exports=function r(e){if(/^\\x/.test(e)){return new Buffer(e.substr(2),"hex")}var t="";var s=0;while(s<e.length){if(e[s]!=="\\"){t+=e[s];++s}else{if(/[0-7]{3}/.test(e.substr(s+1,3))){t+=String.fromCharCode(parseInt(e.substr(s+1,3),8));s+=4}else{var f=1;while(s+f<e.length&&e[s+f]==="\\"){f++}for(var n=0;n<Math.floor(f/2);++n){t+="\\"}s+=Math.floor(f/2)*2}}}return new Buffer(t,"binary")};